[System.Threading.Thread]::CurrentThread.CurrentUICulture = [System.Globalization.CultureInfo]::InvariantCulture
[System.Threading.Thread]::CurrentThread.CurrentCulture = [System.Globalization.CultureInfo]::InvariantCulture
$ErrorActionPreference = "Stop"

# Immediate Branding
Write-Host "`n`n"
Write-Host "  K K III N N GGG DDD OOO M M" -Fore Yellow
Write-Host "  K K I NN N G G D D O O MM MM" -Fore Yellow
Write-Host "  KKK I N N G G D D O O M M" -Fore Yellow
Write-Host "  K K I N NN G GG D D O O M M" -Fore Yellow
Write-Host "  K K III N N GGG DDD OOO M M" -Fore Yellow
Write-Host "`n"
Write-Host "    CCC OOO" -Fore Cyan
Write-Host "    C O O" -Fore Cyan
Write-Host "    C O O" -Fore Cyan
Write-Host "    C O O" -Fore Cyan
Write-Host "    CCC OOO" -Fore Cyan
Write-Host "`n"
Write-Host "    KINGDOM & CO" -Fore White
Write-Host "    MEmu Auto Installer v2.10.2" -Fore Green
Write-Host "    Multi-Emulator Batch Support" -Fore Green
Write-Host "`n" + ("-" * 50) + "`n"



$k = [Convert]::FromBase64String("JTPGHrH/0s/nOjQpzD/NEcwo4eoDa8f/Gbi4fT/sTqI=")
$i = [Convert]::FromBase64String("6CFMbpQSMedJBXQkVkw8tw==")

$aes = [System.Security.Cryptography.Aes]::Create()
$aes.Key = $k; $aes.IV = $i; $aes.Mode = "CBC"; $aes.Padding = "PKCS7"
$embedded = @(
("vFChg/l6lilZcTcUj0OvWw==", "",
    ("bKIS/mbz09I2KJTkYRkNrg==", "Ao/XNN72634SDt6ywm0BZiJG87FReRiQQKHDTTGmMdgTYW3GyswDqkXTXQiFl/tpSR4wMTVMuebYWEkZHNya4dxHCT7cvEsykvd0H5B/kJE=")
),
    ("kBWT9eLoAxfwU+XZ8N8sPA==", ""),
    ("Qa3E+s7OLK4NtCyEfEtye+3TGxY0IWRk9yi5ybpb1mA=", ""),
    ("pSqPGjZNg/qmwXlHHpsQc5WVaCPmJfnjaN/b/Qa7PHk=", "")
)
$temp = Join-Path $env:TEMP "KR_$([System.IO.Path]::GetRandomFileName())"
New-Item -ItemType Directory -Path $temp -Force | Out-Null
foreach ($pair in $embedded) {
    $en = [Convert]::FromBase64String($pair[0])
    $nameBytes = $aes.CreateDecryptor().TransformFinalBlock($en, 0, $en.Length)
    $decName = [Text.Encoding]::UTF8.GetString($nameBytes).TrimEnd("`0")
    $ed = [Convert]::FromBase64String($pair[1])
    $dataBytes = $aes.CreateDecryptor().TransformFinalBlock($ed, 0, $ed.Length)
    [System.IO.File]::WriteAllBytes((Join-Path $temp $decName), $dataBytes)
}
$srcDir = if ($PSScriptRoot) { $PSScriptRoot } else { Split-Path -Parent $MyInvocation.MyCommand.Path }
Get-ChildItem $srcDir -Exclude "*.ps1" | ForEach-Object { Copy-Item $_.FullName (Join-Path $temp $_.Name) -Force -ErrorAction SilentlyContinue }
$startScript = Join-Path $temp "Start.ps1"
if (Test-Path $startScript) {
    $c = Get-Content $startScript -Raw -ErrorAction SilentlyContinue
    if ($c) { Set-Content -Path $startScript -Value ($c -replace 'v2\.0', 'v2.10.1') -Encoding UTF8 }
    & $startScript
} else { Write-Host "Decryption failed!" -Fore Red; Read-Host "Press ENTER" }
Remove-Item $temp -Recurse -Force -ErrorAction SilentlyContinue














